bool isAnagram(char* s, char* t) {
    int cnt[26] = {0};
    for (; *s && *t; s++, t++) {
        cnt[*s - 'a']++;
        cnt[*t - 'a']--;
    }
    if (*s || *t) return false;
    for (int i = 0; i < 26; i++) if (cnt[i]) return false;
    return true;
}
